    { id: 'training', label: 'Training Programs', icon: GraduationCap },
    { id: 'strategy', label: 'AI Strategist', icon: BrainCircuit },
    { id: 'budget', label: 'Budget & Cost', icon: DollarSign },
    { id: 'assets', label: 'Assets & Admin', icon: Building2 },
