export default Sidebar;

import React, { useState } from 'react';
import { Sparkles, Loader2, BookOpen, Target, Clock, ArrowRight } from 'lucide-react';
import { generateTrainingStrategy, analyzeSkillGap } from '../services/geminiService';
import { AIPlanResponse } from '../types';

const AIStrategist: React.FC = () => {
  const [activeMode, setActiveMode] = useState<'create' | 'analyze'>('create');

  // Generation State
  const [topic, setTopic] = useState('');
  const [audience, setAudience] = useState('');
  const [duration, setDuration] = useState('');
  const [loading, setLoading] = useState(false);
  const [generatedPlan, setGeneratedPlan] = useState<AIPlanResponse | null>(null);

  // Analysis State
  const [role, setRole] = useState('');
  const [currentSkills, setCurrentSkills] = useState('');
  const [goal, setGoal] = useState('');
  const [analysisResult, setAnalysisResult] = useState<string>('');

  const handleGenerate = async () => {
    if (!topic || !audience) return;
    setLoading(true);
    const plan = await generateTrainingStrategy(topic, audience, duration);
    setGeneratedPlan(plan);
    setLoading(false);
  };

  const handleAnalyze = async () => {
    if (!role || !currentSkills) return;
    setLoading(true);
    const result = await analyzeSkillGap(role, currentSkills, goal);
    setAnalysisResult(result);
    setLoading(false);
  };

  return (
    <div className="space-y-6 h-full">
      <div className="bg-gradient-to-r from-violet-600 to-indigo-600 rounded-xl p-8 text-white">
        <div className="flex items-center space-x-3 mb-2">
          <Sparkles className="text-yellow-300" />
          <h2 className="text-2xl font-bold">L&D Intelligence Center</h2>
        </div>
        <p className="text-indigo-100 max-w-2xl">
          Leverage Gemini 3.0 to design structured training programs instantly or analyze workforce skill gaps to align with EIB Group goals.
        </p>

        <div className="flex space-x-4 mt-6">
          <button 
            onClick={() => setActiveMode('create')}
            className={`px-4 py-2 rounded-full text-sm font-medium transition-colors ${
              activeMode === 'create' ? 'bg-white text-indigo-600' : 'bg-indigo-700 text-indigo-200 hover:bg-indigo-600'
            }`}
          >
            Curriculum Builder
          </button>
          <button 
            onClick={() => setActiveMode('analyze')}
            className={`px-4 py-2 rounded-full text-sm font-medium transition-colors ${
              activeMode === 'analyze' ? 'bg-white text-indigo-600' : 'bg-indigo-700 text-indigo-200 hover:bg-indigo-600'
            }`}
          >
            Skills Gap Analyzer
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Input Section */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800 mb-6">
            {activeMode === 'create' ? 'Program Parameters' : 'Analysis Context'}
          </h3>

          {activeMode === 'create' ? (
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Training Topic</label>
                <input 
                  type="text" 
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                  className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                  placeholder="e.g., Advanced Project Management"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Target Audience</label>
                <input 
                  type="text" 
                  value={audience}
                  onChange={(e) => setAudience(e.target.value)}
                  className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                  placeholder="e.g., Subsidiary Operations Managers"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Duration</label>
                <select 
                  value={duration}
                  onChange={(e) => setDuration(e.target.value)}
                  className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                >
                  <option value="">Select Duration...</option>
                  <option value="Half Day">Half Day (4 Hours)</option>
                  <option value="Full Day">Full Day (8 Hours)</option>
                  <option value="3 Days">3 Days Intensive</option>
                  <option value="1 Week">1 Week Program</option>
                </select>
              </div>
              <button 
                onClick={handleGenerate}
                disabled={loading || !topic}
                className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-medium rounded-lg flex items-center justify-center space-x-2 transition-all"
              >
                {loading ? <Loader2 className="animate-spin" /> : <Sparkles size={18} />}
                <span>Generate Strategy</span>
              </button>
            </div>
          ) : (
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Job Role</label>
                <input 
                  type="text" 
                  value={role}
                  onChange={(e) => setRole(e.target.value)}
                  className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                  placeholder="e.g., Customer Service Supervisor"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Observed Skills / Issues</label>
                <textarea 
                  value={currentSkills}
                  onChange={(e) => setCurrentSkills(e.target.value)}
                  className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none h-24 resize-none"
                  placeholder="e.g., Good technical knowledge but struggles with conflict resolution and team motivation."
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Business Goal</label>
                <input 
                  type="text" 
                  value={goal}
                  onChange={(e) => setGoal(e.target.value)}
                  className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                  placeholder="e.g., Improve customer retention by 15%"
                />
              </div>
              <button 
                onClick={handleAnalyze}
                disabled={loading || !role}
                className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-medium rounded-lg flex items-center justify-center space-x-2 transition-all"
              >
                {loading ? <Loader2 className="animate-spin" /> : <Target size={18} />}
                <span>Analyze Gaps</span>
              </button>
            </div>
          )}
        </div>

        {/* Output Section */}
        <div className="bg-slate-50 p-6 rounded-xl border border-slate-200 h-full overflow-y-auto max-h-[600px]">
          {loading ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-400">
              <Loader2 className="w-10 h-10 animate-spin mb-4 text-indigo-500" />
              <p>Consulting Intelligence Models...</p>
            </div>
          ) : activeMode === 'create' && generatedPlan ? (
            <div className="space-y-6">
              <div className="border-b border-slate-200 pb-4">
                <h2 className="text-2xl font-bold text-slate-800">{generatedPlan.title}</h2>
                <p className="text-slate-600 mt-2">{generatedPlan.overview}</p>
              </div>
              <div className="space-y-4">
                {generatedPlan.modules.map((mod, idx) => (
                  <div key={idx} className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm">
                    <div className="flex justify-between items-start">
                      <h4 className="font-bold text-slate-800 flex items-center">
                        <span className="bg-indigo-100 text-indigo-700 w-6 h-6 rounded-full flex items-center justify-center text-xs mr-2">{idx + 1}</span>
                        {mod.name}
                      </h4>
                      <div className="flex items-center text-xs text-slate-500 bg-slate-100 px-2 py-1 rounded">
                        <Clock size={12} className="mr-1" />
                        {mod.duration}
                      </div>
                    </div>
                    <ul className="mt-3 space-y-2">
                      {mod.objectives.map((obj, i) => (
                        <li key={i} className="flex items-start text-sm text-slate-600">
                          <ArrowRight size={14} className="mr-2 mt-1 text-emerald-500 flex-shrink-0" />
                          {obj}
                        </li>
                      ))}
                    </ul>
                  </div>
                ))}
              </div>
              <button className="w-full py-2 border-2 border-indigo-600 text-indigo-700 font-medium rounded-lg hover:bg-indigo-50 transition-colors">
                Save to Training Calendar
              </button>
            </div>
          ) : activeMode === 'analyze' && analysisResult ? (
            <div className="prose prose-slate max-w-none">
                <h3 className="text-xl font-bold text-slate-800 mb-4">Gap Analysis Report</h3>
                <div className="whitespace-pre-wrap text-slate-700 text-sm leading-relaxed">
                    {analysisResult}
                </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-400">
              <BookOpen className="w-12 h-12 mb-4 opacity-50" />
              <p>Generated strategy or analysis will appear here.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AIStrategist;

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip } from 'recharts';
import { TrendingDown, TrendingUp, AlertTriangle } from 'lucide-react';
import { BudgetRecord } from '../types';

const budgetData: BudgetRecord[] = [
  { category: 'External Vendors', allocated: 50000, spent: 42000, variance: 8000 },
  { category: 'Digital Learning Tools', allocated: 15000, spent: 12500, variance: 2500 },
  { category: 'Venues & Catering', allocated: 20000, spent: 22000, variance: -2000 },
  { category: 'Staff Onboarding', allocated: 10000, spent: 4000, variance: 6000 },
];

const COLORS = ['#3b82f6', '#10b981', '#f43f5e', '#8b5cf6'];

const BudgetManager: React.FC = () => {
  const totalBudget = budgetData.reduce((acc, curr) => acc + curr.allocated, 0);
  const totalSpent = budgetData.reduce((acc, curr) => acc + curr.spent, 0);
  const remaining = totalBudget - totalSpent;

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row gap-6">
        {/* Summary Card */}
        <div className="flex-1 bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col justify-center">
            <h3 className="text-slate-500 font-medium text-sm">Total Annual Budget</h3>
            <div className="text-4xl font-bold text-slate-800 mt-2">${totalBudget.toLocaleString()}</div>
            <div className="mt-6 flex items-center space-x-4">
                <div>
                    <span className="text-xs text-slate-400 block">SPENT</span>
                    <span className="text-lg font-bold text-rose-600">${totalSpent.toLocaleString()}</span>
                </div>
                <div className="h-8 w-[1px] bg-slate-200"></div>
                <div>
                    <span className="text-xs text-slate-400 block">REMAINING</span>
                    <span className="text-lg font-bold text-emerald-600">${remaining.toLocaleString()}</span>
                </div>
            </div>
            <div className="w-full bg-slate-100 rounded-full h-2 mt-4 overflow-hidden">
                <div className="bg-blue-600 h-full rounded-full" style={{ width: `${(totalSpent/totalBudget)*100}%`}}></div>
            </div>
        </div>

        {/* Visual Distribution */}
        <div className="flex-1 bg-white p-6 rounded-xl shadow-sm border border-slate-200 min-h-[300px]">
            <h3 className="text-lg font-bold text-slate-800 mb-2">Cost Distribution</h3>
            <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                    <Pie
                        data={budgetData}
                        cx="50%"
                        cy="50%"
                        innerRadius={60}
                        outerRadius={80}
                        paddingAngle={5}
                        dataKey="spent"
                    >
                        {budgetData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                        ))}
                    </Pie>
                    <Tooltip />
                    <Legend verticalAlign="bottom" height={36}/>
                </PieChart>
            </ResponsiveContainer>
        </div>
      </div>

      {/* Variance Table */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-200">
            <h3 className="text-lg font-bold text-slate-800">Budget Variance Report (Forecast vs Actual)</h3>
        </div>
        <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-xs uppercase font-semibold">
                <tr>
                    <th className="px-6 py-4">Category</th>
                    <th className="px-6 py-4">Allocated</th>
                    <th className="px-6 py-4">Actual Spend</th>
                    <th className="px-6 py-4">Variance</th>
                    <th className="px-6 py-4">Status</th>
                </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
                {budgetData.map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-50">
                        <td className="px-6 py-4 font-medium text-slate-800">{item.category}</td>
                        <td className="px-6 py-4 text-slate-600">${item.allocated.toLocaleString()}</td>
                        <td className="px-6 py-4 text-slate-600">${item.spent.toLocaleString()}</td>
                        <td className={`px-6 py-4 font-bold ${item.variance < 0 ? 'text-rose-500' : 'text-emerald-500'}`}>
                            {item.variance < 0 ? '-' : '+'}${Math.abs(item.variance).toLocaleString()}
                        </td>
                        <td className="px-6 py-4">
                            {item.variance < 0 ? (
                                <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-rose-100 text-rose-800">
                                    <AlertTriangle size={12} className="mr-1"/> Overrun
                                </span>
                            ) : (
                                <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-emerald-100 text-emerald-800">
                                    <TrendingDown size={12} className="mr-1"/> Efficient
                                </span>
                            )}
                        </td>
                    </tr>
                ))}
            </tbody>
        </table>
      </div>
    </div>
  );
};

export default BudgetManager;

import React, { useState } from 'react';
