const TrainingManager: React.FC<TrainingManagerProps> = ({ user }) => {
  const [submissions, setSubmissions] = useState<ProgramSubmission[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // Fetch Real Data from Supabase
  useEffect(() => {
    const fetchSubmissions = async () => {
      setLoading(true);

      // RLS Policy on Supabase automatically handles filtering:
      // - Group Admins get all rows
      // - Subsidiary Managers get only their rows
      // So we just select *
      const { data, error } = await supabase
        .from('training_submissions')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) {
        console.error('Error fetching submissions:', error);
      } else if (data) {
        // Map DB Snake Case to our App's Camel Case Types
        const mappedData: ProgramSubmission[] = data.map((item: any) => ({
            id: item.id,
            title: item.title,
            submittedBy: item.submitted_by_name || 'Unknown', // You might need to join profiles in query
            submissionDate: new Date(item.created_at).toLocaleDateString(),
            subsidiary: item.subsidiary,
            version: item.version,
            status: item.status,
            complianceScore: item.compliance_score,
            overview: item.overview,
            modules: item.content || [], // JSONB column
            requestNotes: item.request_notes
        }));

        setSubmissions(mappedData);
        if (mappedData.length > 0) setSelectedId(mappedData[0].id);
      }
      setLoading(false);
    };

    fetchSubmissions();
  }, [user]);

  const selectedProgram = submissions.find(s => s.id === selectedId);

  const handleStatusChange = async (id: string, newStatus: ProgramSubmission['status']) => {
    // Optimistic Update
    setSubmissions(prev => prev.map(s => 
      s.id === id ? { ...s, status: newStatus } : s
    ));

    // Real DB Update
    const { error } = await supabase
        .from('training_submissions')
        .update({ status: newStatus })
        .eq('id', id);

    if (error) {
        console.error('Error updating status:', error);
        // Revert on error (optional implementation)
    }
  };

  if (loading) {
      return (
          <div className="h-[500px] flex items-center justify-center">
              <Loader2 className="animate-spin text-slate-400" size={32} />
          </div>
